(self.webpackChunkcheatsheet=self.webpackChunkcheatsheet||[]).push([[8975],{9983:(e,s,a)=>{"use strict";a.r(s),a.d(s,{data:()=>n});const n={key:"v-9a11be3a",path:"/sql/view/select/",title:"SELECT & FROM",lang:"en-US",frontmatter:{},excerpt:"",headers:[{level:3,title:"เลือกทั้งหมด",slug:"เลือกทั้งหมด",children:[]},{level:2,title:"เลือกบาง Column จากตาราง",slug:"เลือกบาง-column-จากตาราง",children:[]},{level:2,title:"Select DISTINCT column",slug:"select-distinct-column",children:[{level:3,title:"Modify the result with calculations",slug:"modify-the-result-with-calculations",children:[]}]},{level:2,title:"Change column name",slug:"change-column-name",children:[{level:3,title:"Temporary change column name with AS",slug:"temporary-change-column-name-with-as",children:[]},{level:3,title:"Use CONCAT to merge row-column value",slug:"use-concat-to-merge-row-column-value",children:[]}]}],filePathRelative:"sql/view/select/README.md",git:{updatedTime:162676698e4,contributors:[]}}},4942:(e,s,a)=>{"use strict";a.r(s),a.d(s,{default:()=>r});var n=a(6252);const l=(0,n.uE)('<h1 id="select-from" tabindex="-1"><a class="header-anchor" href="#select-from" aria-hidden="true">#</a> SELECT &amp; FROM</h1><p>เพื่อที่จะเข้าถึงข้อมูลภายใน Database เราจะต้องใช้คำสั่งนั่นก็คือ <code>SELECT</code> และ <code>FROM</code> โดยที่ <code>SELECT</code> จะทำหน้าที่เลือก column ที่เกี่ยวข้องในตารางออกมา และ <code>FROM</code> จะทำหน้าที่เลือก table ที่เกี่ยวข้องในตารางออกมา</p><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code><span class="token keyword">SELECT</span> <span class="token punctuation">[</span>column_name<span class="token punctuation">]</span>\n<span class="token keyword">FROM</span> <span class="token punctuation">[</span>table_name<span class="token punctuation">]</span><span class="token punctuation">;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><div class="custom-container tip"><p class="custom-container-title">TIP</p><p>เราควรที่จะเลือก column ที่เราต้องการใช้งานเท่านั้นเพื่อทำให้การใช้งานของผู้ใช้นั้นเร็วขึ้น</p></div><h3 id="เลือกทั้งหมด" tabindex="-1"><a class="header-anchor" href="#เลือกทั้งหมด" aria-hidden="true">#</a> เลือกทั้งหมด</h3><p>เพื่อที่จะเลือกทุก column ออกมา ให้ใช้ <code>SELECT *</code></p><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code><span class="token keyword">SELECT</span> <span class="token operator">*</span>\n<span class="token keyword">FROM</span> Employees<span class="token punctuation">;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><div class="custom-container tip"><p class="custom-container-title">TIP</p><p>ข้อดี: หากว่ามีคนทำการลบชื่อ column ออกไป เราก็จะไม่ได้รับผลกระทบอะไร เพราะก็เลือกทุกอันอยู่แล้ว</p><p>ข้อเสีย: ช้ากว่าการเรียกบาง column</p></div><h2 id="เลือกบาง-column-จากตาราง" tabindex="-1"><a class="header-anchor" href="#เลือกบาง-column-จากตาราง" aria-hidden="true">#</a> เลือกบาง Column จากตาราง</h2><p>เพื่อที่จะเลือกบาง column ออกมา ให้เขียนชื่อ column หลังจาก SELECT และตามด้วย , หากต้องการหลาย column</p><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code><span class="token keyword">SELECT</span> first_name<span class="token punctuation">,</span> last_name\n<span class="token keyword">FROM</span> Employees<span class="token punctuation">;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="select-distinct-column" tabindex="-1"><a class="header-anchor" href="#select-distinct-column" aria-hidden="true">#</a> Select <code>DISTINCT</code> column</h2><p><code>DISTINCT</code> keyword is used when you want to get a <em>unique</em> values as a output. So the result does not have duplicate values in that selected column(s).</p><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code><span class="token keyword">SELECT</span> <span class="token keyword">DISTINCT</span> salary\n<span class="token keyword">FROM</span> Employees<span class="token punctuation">;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>the result will not have duplicates (because using <code>DISTINCT</code> keyword)</p><h3 id="modify-the-result-with-calculations" tabindex="-1"><a class="header-anchor" href="#modify-the-result-with-calculations" aria-hidden="true">#</a> Modify the result with calculations</h3><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code><span class="token keyword">SELECT</span> salary<span class="token punctuation">,</span> salary <span class="token operator">*</span> <span class="token number">100</span>\n<span class="token keyword">FROM</span> Employees<span class="token punctuation">;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>and that will show the salary column and the column that is a value of the salary times 100.</p><h2 id="change-column-name" tabindex="-1"><a class="header-anchor" href="#change-column-name" aria-hidden="true">#</a> Change column name</h2><h3 id="temporary-change-column-name-with-as" tabindex="-1"><a class="header-anchor" href="#temporary-change-column-name-with-as" aria-hidden="true">#</a> Temporary change column name with <code>AS</code></h3><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code><span class="token keyword">SELECT</span> first_name <span class="token keyword">AS</span> <span class="token punctuation">`</span><span class="token keyword">First</span> Name<span class="token punctuation">`</span>\n<span class="token keyword">FROM</span> Employees<span class="token punctuation">;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><code>AS</code> keyword also can be skipped. NOTE : use backslash ` to marked it as a string</p><h3 id="use-concat-to-merge-row-column-value" tabindex="-1"><a class="header-anchor" href="#use-concat-to-merge-row-column-value" aria-hidden="true">#</a> Use <code>CONCAT</code> to merge row-column value</h3><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code><span class="token keyword">SELECT</span> CONCAT<span class="token punctuation">(</span>last_name<span class="token punctuation">,</span> <span class="token string">&#39; is a &#39;</span><span class="token punctuation">,</span> job_id<span class="token punctuation">)</span>\n    <span class="token keyword">AS</span> <span class="token punctuation">`</span>Employee Details<span class="token punctuation">`</span>\n<span class="token keyword">FROM</span> Employees<span class="token punctuation">;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><hr><h4 id="resource" tabindex="-1"><a class="header-anchor" href="#resource" aria-hidden="true">#</a> Resource</h4>',26),c=(0,n.Uk)("CodeAcademy "),t={href:"https://www.codecademy.com/courses/learn-sql/lessons/queries/exercises/distinct?action=resume_content_item",target:"_blank",rel:"noopener noreferrer"},o=(0,n.Uk)("https://www.codecademy.com/courses/learn-sql/lessons/queries/exercises/distinct?action=resume_content_item"),r={render:function(e,s){const a=(0,n.up)("OutboundLink");return(0,n.wg)(),(0,n.j4)(n.HY,null,[l,(0,n.Wm)("ul",null,[(0,n.Wm)("li",null,[c,(0,n.Wm)("a",t,[o,(0,n.Wm)(a)])])])],64)}}}}]);